#!/usr/bin/env node
console.log("🕐 VPS Time Check Script"),console.log("=".repeat(40));const now=new Date;console.log(`Current time: ${now.toString()}`),console.log(`ISO string: ${now.toISOString()}`),console.log(`UTC time: ${now.toUTCString()}`),console.log(`Local timezone: ${Intl.DateTimeFormat().resolvedOptions().timeZone}`);const unixTimestamp=Math.floor(now.getTime()/1e3);console.log(`Unix timestamp: ${unixTimestamp}`);const expectedTime=new Date,timeDiff=Math.abs(now.getTime()-expectedTime.getTime());timeDiff>6e4?(console.log("⚠️ WARNING: System time appears to be significantly off!"),console.log(`Time difference: ${timeDiff/1e3} seconds`)):console.log("✅ System time appears to be accurate"),console.log("\n🌍 Environment:"),console.log(`Node.js version: ${process.version}`),console.log(`Platform: ${process.platform}`),console.log(`Architecture: ${process.arch}`);try{const fs=require("fs");if(fs.existsSync("/.dockerenv"))console.log("🐳 Running in Docker container");else if(fs.existsSync("/proc/1/cgroup")){const cgroup=fs.readFileSync("/proc/1/cgroup","utf8");(cgroup.includes("docker")||cgroup.includes("kubectl"))&&console.log("🐳 Running in containerized environment")}}catch(error){}console.log("\n"+"=".repeat(40)),console.log("💡 If time is wrong, check:"),console.log("   - VPS system clock: sudo date"),console.log("   - Timezone: sudo timedatectl"),console.log("   - NTP sync: sudo ntpq -p"),console.log("   - Container time sync if using Docker");